3.1.1 Linear Regression in a ML Context



{
    //
    const randomDataRange = [-4, 4];
    const lossRange = [0, 11];

    // Generate random data
    const seed = 0.25160386911120525; // a number in [0,1)
    const source = d3.randomLcg(seed);
    const randn = d3.randomNormal.source(source)(0, 1);
    let xTmp = Array.from({length: 100}, randn);
    let yTmp = Array.from({length: 100}, randn);
    let randomData = prepareData(xTmp, yTmp);

    function prepareData(xTmp, yTmp) {

        let data = [];

        for (let i = 0; i &lt; xTmp.length; i += 1) {
            let dataPoint = {"x": xTmp[i], "y": xTmp[i] + yTmp[i]};
            data.push(dataPoint)
        }

        return data;

    }

    // Loss function
    function sumOfSquares(slope) {

        let sum = 0;

        for (let i = 0; i &lt; randomData.length; i += 1) {
            sum += (randomData[i].y - slope * randomData[i].x) ** 2 / randomData.length;
        }

        return sum;

    }

    function computeLossCurve(inputRange) {

        let loss = [];
        let N = 100;

        for (let i = 0; i &lt;= 100; i += 1) {
            let x = inputRange[0] + i * (inputRange[1] - inputRange[0])/100
            let dataPoint = {"x": x, "y": sumOfSquares(x)};
            loss.push(dataPoint)
        }

        return loss;

    }

    // Data for regression line
    let slopeData = [
        {x: (slope &gt; 1 || slope &lt; -1)  ? randomDataRange[0]/slope : randomDataRange[0], y: (slope &gt; 1 || slope &lt; -1)  ? randomDataRange[0] : randomDataRange[0]*slope},
        {x: (slope &gt; 1 || slope &lt; -1)  ? randomDataRange[1]/slope : randomDataRange[1], y: (slope &gt; 1 || slope &lt; -1)  ? randomDataRange[1] : randomDataRange[1]*slope}
    ];

    // Data for loss marker
    let markerData = [
        {x: slope, y: sumOfSquares(slope) }
    ];

    // Data for loss curve
    let lossCurveData = computeLossCurve(inputRange);

    const sets = [1, 2];
    return html`&lt;div style="display:flex; flex-wrap: wrap;"&gt;
    ${sets
    .map((index) =&gt;
        Plot.plot({
            marginLeft: 40,
            marginTop: 20,
            width: width / 2 - 2,
            height: width / 3 - 2,
            x: { domain: index === 1 ? randomDataRange : inputRange, label: index === 1 ? "x" : "Weight"},
            y: { domain: index === 1 ? randomDataRange : lossRange, label: index === 1 ? "y" : "Loss"},
            marks: [
                Plot.frame(),
                index === 1
                    ? Plot.dot(randomData, {x: "x", y: "y", fill: "steelblue"})
                    : Plot.line(lossCurveData, {x: "x", y: "y", stroke: "steelblue"}),
                index === 1
                    ? Plot.line(slopeData, {x: "x", y: "y", stroke: "red"})
                    : Plot.dot(markerData, {x: "x", y: "y", fill: "red", r: 6}),
                Plot.text([index], {
                    x: index === 1 ? (randomDataRange[1] + randomDataRange[0])/2 : (inputRange[1] + inputRange[0])/2,
                    y: index === 1 ? ((randomDataRange[1] - randomDataRange[0]) * 0.1 + randomDataRange[1]) : ((lossRange[1] - lossRange[0]) * 0.1 + lossRange[1]),
                    text: (d) =&gt; index === 1 ? "Data + Regression Line" : "Mean Squared Error (MSE)",
                    textAnchor: "middle"
                })
            ],
            nice: true
        })
    )
    .flat()}`;
}







inputRange = [-2, 4];
viewof slope = Inputs.range(inputRange, {label: "Weight (w)", step: 0.01})

















Figure 3.1: Interactive Linear Regression With a Single Feature \(x\) (i.e., \(m=1\)) and Bias \(b=0\)


You have already extensively studied linear regressions in courses of the program, so we will not discuss it in much detail. In machine learning, it is common to talk about weights \(w_i\) and biases \(b_i\) instead of coefficients \(\beta_i\) and intercept \(\beta_0\), i.e., the linear regression model would be written as
\[y_n = b + \sum_{i=1}^m w_i x_{i,n} + \varepsilon_n \qquad n=1,\ldots,N\]
where \(w_i\) are the weights, \(b\) is the bias and \(N\) is the sample size. The weights and biases are found by minimizing the empirical risk function or mean squared error (MSE) loss, which is a measure of how well the model fits the data.
\[\text{MSE}(y,x; w, b) = \frac{1}{N}\sum_{n=1}^N (y_n - \hat{y}_n)^2\]
where \(y_n\) is the true value, \(\hat{y}_n\) is the predicted (or fitted) value for observation \(n\).
In the case of linear regression, there is a closed-form solution for the weights and biases that minimize the MSE. However, the weights and biases have to be found numerically in many other machine learning models since there is no closed-form solution. One can think of this, as the machine learning algorithm automatically moving a slider for the slope Figure 3.2 until the loss is minimized (i.e., the red dot is at the lowest possible point) and the model fits the data as well as possible.


3.1.2 Logistic Regression in a ML Context
Logistic regression is a widely used classification model \(p(y|x;w,b)\) where \(x\in \mathbb{R}^m\) is an input vector, and \(y\in\{0,1,\ldots,C\}\) is a class label. We will focus on the binary case, meaning that \(y\in\{0,1\}\) but it is also possible to extend this to more than two classes. The probability that \(y_n\) is equal to \(1\) for observation \(n\) is given by \[p(y_n=1|x_n;w,b)= \frac{1}{1+\exp(-b-\sum_{i=1}^m w_i x_{i,n})}\]
where \(w=[w_1, \ldots, w_m]'\in \mathbb{R}^m\) is a weight vector, and \(b\) is a bias term. Combining the probabilities for each observation \(n\), we can write the likelihood function as
\[\mathcal{L}(w,b) = \prod_{n=1}^N p(y_n=1|x_n;w,b)^{y_n} \left(1-p(y_n=1|x_n;w,b)\right)^{1-y_n}\]
or taking the natural logarithm of the likelihood function, we get the log-likelihood function
\[\log\mathcal{L}(w,b) = \sum_{n=1}^N y_n \log p(y_n=1|x_n;w,b) + (1-y_n) \log \left(1-p(y_n=1|x_n;w,b)\right).\]
To find the weights and biases, we need to numerically maximize the log-likelihood function (or minimize \(-\log\mathcal{L}(w,b)\)).
Adding a classification threshold \(t\) to a logistic regression yields a decision rule of the form
\[\hat{y}=1 \Leftrightarrow p(y=1|x;w,b) &gt; t,\]
i.e., the model predicts that \(y=1\) if \(p(y=1|x;w,b) &gt; t\).



{
    //
    const randomDataRange = [-2, 2];
    const loglikelihoodRange = [-20, -8];

    // Generate random data
    const seed = 0.25160386911120525; // a number in [0,1)
    const source = d3.randomLcg(seed);
    const rand = d3.randomUniform.source(source)();
    let xTmp = Array.from({length: 100}, rand).map((x) =&gt; 4*x-2);
    let pTmp = xTmp.map((x) =&gt; 1/(1+Math.exp(-8*x)));
    let cTmp = xTmp.map((x) =&gt; (1/(1+Math.exp(-slope2*x)) &gt;= thresholdValue) ? 1 : 0); // Classification based on threshold and slope2
    let yTmp = pTmp.map((p) =&gt; Array.from({length: 1}, rand)[0] &lt; p ? 1 : 0);
    let randomData = prepareData(xTmp, yTmp, cTmp);

    function prepareData(xTmp, yTmp, cTmp) {

        let data = [];

        for (let i = 0; i &lt; xTmp.length; i += 1) {
            let dataPoint = {"x": xTmp[i], "y": yTmp[i], "class": cTmp[i]};
            data.push(dataPoint)
        }

        return data;

    }

    // Regression line
    let regData = computeLogisticRegressionLine(slope2, randomDataRange, 100)

    function computeLogisticRegressionLine(slope, inputRange, N) {

        let data = [];

        for (let i = 0; i &lt;= N; i += 1) {
            let x = inputRange[0] + i * (inputRange[1] - inputRange[0])/100;
            let dataPoint = {"x": x, "y": 1/(1+Math.exp(-slope*x))};
            data.push(dataPoint);
        }

        return data;

    }

    // Log-likelihood function
    function computeLogLikelihood(slope, data) {

        let loglikelihood = 0;

        for (let i = 0; i &lt; data.length; i += 1) {
            loglikelihood += data[i].y * Math.log(1/(1+Math.exp(-slope*data[i].x))) + (1-data[i].y) * Math.log(1-1/(1+Math.exp(-slope*data[i].x)));
        }

        return loglikelihood;

    }

    function computeLossCurve(inputRange, data, N) {

        let loss = [];

        for (let i = 0; i &lt;= N; i += 1) {
            let x = inputRange[0] + i * (inputRange[1] - inputRange[0])/100;
            let dataPoint = {"x": x, "y": computeLogLikelihood(x, data)};
            loss.push(dataPoint);
        }

        return loss;

    }

    let loglikelihoodCurveData = computeLossCurve(inputRange2, randomData, 100);
    let markerData = [
        {x: slope2, y: computeLogLikelihood(slope2, randomData) }
    ];

    // Data for threshold
    let threshData = [
        {x: randomDataRange[0], y: thresholdValue},
        {x: randomDataRange[1], y: thresholdValue}
    ];

    const sets = [1, 2];
    return html`&lt;div style="display:flex; flex-wrap: wrap;"&gt;
    ${sets
    .map((index) =&gt;
        Plot.plot({
            marginLeft: 40,
            marginTop: 20,
            width: width / 2 - 2,
            height: width / 3 - 2,
            x: { domain: index === 1 ? [-2, 2] : inputRange2, label: index === 1 ? "X" : "Weight"},
            y: { domain: index === 1 ? [0, 1] : loglikelihoodRange, label: index === 1 ? "Y" : "log(L(w,b))"},
            color: {
                domain: [0, 1],
                scheme: "Paired"
            },
            marks: [
                Plot.frame(),
                index === 1
                    ? Plot.dot(randomData, {x: "x", y: "y", r: 4, fill: threshold.includes("") ? "class" : "steelblue"})
                    : Plot.line(loglikelihoodCurveData, {x: "x", y: "y", stroke: "steelblue"}),
                index === 1
                    ? Plot.line(regData, {x: "x", y: "y", stroke: "red"})
                    : Plot.dot(markerData, {x: "x", y: "y", fill: "red", r: 6}),
                threshold.includes("")
                    ? Plot.line(threshData, {x: "x", y: "y", stroke: "black", strokeDasharray: "10,5"})
                    : null,
                Plot.text([index], {
                    x: index === 1 ? (randomDataRange[1] + randomDataRange[0])/2 : (inputRange2[1] + inputRange2[0])/2,
                    y: index === 1 ? 1.1 : ((loglikelihoodRange[1] - loglikelihoodRange[0]) * 0.1 + loglikelihoodRange[1]),
                    text: (d) =&gt; index === 1 ? "Data + Regression Line" : "Log-Likelihood",
                    textAnchor: "middle"
                })
            ],

            nice: true
        })
    )
    .flat()}`;
}







inputRange2 = [-2, 18];
viewof slope2 = Inputs.range(inputRange2, {label: "Weight (w)", step: 0.01})
viewof threshold = Inputs.checkbox([""], {label: "Classification Threshold"})
viewof thresholdValue = Inputs.range([0,1], {value: 0.5, label: "Threshold Value (t)", step: 0.01})































Figure 3.3: Interactive Logistic Regression With a Single Feature \(x\) (i.e., \(m=1\)) and Bias \(b=0\) (Classification Legend: dark blue = 1, light blue = 0)








WarningTerminology: Regression vs. Classification



Do not get confused about the fact that it is called logistic regression but is used for classification tasks. Logistic regression provides an estimate of the probability that \(y=1\) for given \(x\), i.e., an estimate for \(p(y=1|x;w,b)\). To turn, this into a classification model, we also need a classification threshold value for \(p(y=1|x;w,b)\) above which we classify an observation as \(y=1\).


Figure 3.4 shows an interactive example of a logistic regression model. The left-hand side shows the data points and the regression line. The right-hand side shows the log-likelihood function with the red dot showing the value of the log-likelihood for the current value of \(w\). The goal is to find the weight \(w\) in the regression line that maximizes the log-likelihood function (we assumed \(b=0\) for simplicity).
If you enable the classification threshold \(t\), a data point is shown as dark blue if \(p(y=1|x;w,b) &gt; t\), otherwise, it is shown in light blue. Note how the value of the threshold affects the classification of the data points for points in the middle. Essentially, for each classification threshold, we have a different classification model. But how do we choose the classification threshold? This is a topic that we will discuss in the next section.
Logistic regression belongs to the class of generalized linear models with logit as the link function. We could write
\[\log\left(\frac{p}{1-p}\right)= b+\sum_{i=1}^m w_i x_{i,n}\]
where \(p=p(y_n=1|x_n;w,b)\), which separates the linear part on the right-hand side from the logit on the left-hand side.



{
    //
    const randomDataRange = [-2, 2];
    const loglikelihoodRange = [-20, -8];

    // Generate random data
    const seed = 0.25160386911120525; // a number in [0,1)
    const source = d3.randomLcg(seed);
    const rand = d3.randomUniform.source(source)();
    let x1Tmp = Array.from({length: 200}, rand).map((x) =&gt; (randomDataRange[1] - randomDataRange[0]) * x + randomDataRange[0]);
    let x2Tmp = Array.from({length: 200}, rand).map((x) =&gt; (randomDataRange[1] - randomDataRange[0]) * x + randomDataRange[0]);
    let pTmp = x1Tmp.map((x1, i) =&gt; 1/(1+Math.exp(-0.5 - 3 * x1 - 4 * x2Tmp[i] - 2 * Math.pow(x1, 2)))); // "True" model
    //(usSquare.includes("") ? 2 * Math.pow(x1, 2) : 0)
    let yTmp = pTmp.map((p) =&gt; Array.from({length: 1}, rand)[0] &lt; p ? 1 : 0);
    let randomData = prepareData(yTmp, x1Tmp, x2Tmp);

    function prepareData(yTmp, x1Tmp, x2Tmp) {

        let data = [];

        for (let i = 0; i &lt; x1Tmp.length; i += 1) {
            let dataPoint = {"x1": x1Tmp[i], "x2": x2Tmp[i], "y": yTmp[i]};
            data.push(dataPoint)
        }

        return data;

    }

    // Decision boundary
    let regData = computeDecisionBoundary(weight1, weight2, weight3, bias, 0.5, randomDataRange, 100)

    function computeDecisionBoundary(w1, w2, w3, b, t, inputRange, N) {

        let data = [];

        for (let i = 0; i &lt;= N; i += 1) {
            let x1 = inputRange[0] + i * (inputRange[1] - inputRange[0])/100;
            let x2 = 1/w2 * (-b - w1 * x1 - (useSquare.includes("") ? w3 * Math.pow(x1,2)  : 0) - Math.log((1-t)/t));
            x2 = Math.min(Math.max(x2, inputRange[0]), inputRange[1])
            let c = 1/(1+Math.exp(-b - w1 * x1 - w2 * x2 - 2 * Math.pow(x1, 2) + 3 * Math.pow(x1, 3)) &lt; t ? 0 : 1);
            let dataPoint = {"x1": x1, "x2": x2, "lb": inputRange[0], "ub": inputRange[1], "c0": 0, "c1": 1};
            data.push(dataPoint);
        }

        return data;

    }


    return Plot.plot({
            marginLeft: 40,
            marginTop: 20,
            width: width - 2,
            height: width * 2/3 - 2,
            x: { domain: randomDataRange, label: "x₁"},
            y: { domain: randomDataRange, label: "x₂"},
            color: {
                domain: [0, 1],
                scheme: "Category10"
            },
            marks: [
                Plot.frame(),
                Plot.dot(randomData, {x: "x1", y: "x2", r: 4, fill: "y"}),
                Plot.areaY(regData, {x: "x1", y: "x2", y2: "lb", fill: "c0", fillOpacity: 0.2}),
                Plot.areaY(regData, {x: "x1", y: "x2", y2: "ub", fill: "c1", fillOpacity: 0.2}),
                Plot.line(regData, {x: "x1", y: "x2"})
            ],

            nice: true
        })
}







viewof weight1 = Inputs.range([-5, 5], {value: 3, label: "Weight w₁", step: 0.01})
viewof weight2 = Inputs.range([0.1, 10], {value: 4, label: "Weight w₂", step: 0.01})
viewof bias = Inputs.range([-10, 10], {value: 0.5, label: "Bias b", step: 0.01})
viewof useSquare = Inputs.checkbox([""], {label: "Include square of x₁"})
viewof weight3 = Inputs.range([-5, 5], {value: 2, label: "w₃", step: 0.01})






































Figure 3.5: Decision Boundary - Logistic Regression with Features \(x_1\) and \(x_2\) (and optionally \(x_1^2\))


This linearity also shows up in the linear decision boundary produced by a logistic regression in Figure 3.6. A decision boundary shows how a machine-learning model separates different classes in our data, i.e, how it would classify an arbitrary combination of \((x_1,x_2)\). This linearity of the decision boundary can pose a problem if the two classes are not linearly separable as in Figure 3.6. We can remedy this issue by including higher order terms for \(x_1\) and \(x_2\) such as \(x_1^2\) or \(x_2^3\), which is a type of feature engineering. However, there are many forms of non-linearity that the decision boundary can have and we cannot try all of them. You might know the following phrase from a Tolstoy book

“Happy families are all alike; every unhappy family is unhappy in its own way.”

In the context of non-linear functions, people sometimes say

“Linear functions are all alike; every non-linear function is non-linear in its own way.”

During the course, we will learn more advanced machine-learning techniques that can produce non-linear decision boundaries without the need for feature engineering.


3.1.3 K-Nearest Neighbors
The K-Nearest Neighbors (KNN) algorithm is a simple and intuitive method for classification and regression. The KNN algorithm uses the \(K\) nearest neighbors of a data point to make a prediction. For example, in the case of a regression task, the prediction \(\hat{y}\) for a new data point \(x\) is
\[\hat{y} = \frac{1}{K}\sum_{x_i\in N_k(x)} y_i\]
i.e., the average of the \(K\) nearest neighbors of \(x\). In the case of a classification task, the prediction \(\hat{y}\) is the majority class of the \(K\) nearest neighbors of \(x\).














Figure 3.7: K-Nearest Neighbors Classification with \(K=5\) (Classification shown as Shaded Area)



Figure 3.7 shows an example of the K-Nearest Neighbors algorithm applied to the dataset that was used for the logistic regression example in Figure 3.4. For each point in the feature space, the KNN algorithm looks at the \(K=5\) nearest neighbors and classifies the point based on the majority class of these neighbors. Note that the color of the data point is the true value, while the shaded area shows the classification made by the KNN algorithm.
The decision boundary is highly non-linear and can adapt to the shape of the data. However, this flexibility comes at a cost. The KNN algorithm can be computationally expensive, especially for large datasets, since it needs to compute the distance between the new data point and all other data points in the training set. Additionally, the KNN algorithm is sensitive to the choice of \(K\) and the distance metric used to compute the nearest neighbors.
In the example, above we used the Euclidean distance to compute the nearest neighbors. The squared Euclidean distance between two points \(x\) and \(y\) in \(p\)-dimensional space is defined as
\[d(x_i, x_j) = \sum_{n=1}^p (x_{in} - x_{jn})^2=\lVert x_i - x_j \rVert^2\]
where \(x_{in}\) and \(x_{jn}\) are the \(n\)-th feature of the \(i\)-th and \(j\)-th observation in our dataset, respectively.
Note that the Euclidean distance can be used in both regression and classification problems since it only applies to the features \(x\) and not the target variable \(y\). However, if the features include categorical variables, we need to use a different distance metric that can accommodate such variables.

3.3 Generalization and Overfitting
Typically, we are not just interested in having a good fit for the dataset on which we are training a classification (or regression) model, after all, we already have the actual classes or realization of predicted variables in our dataset. What we are really interested in is that a classification or regression model generalizes to new data.
However, since the models that we are using are highly flexible, it can be the case that we have a very high accuracy during the training of our model but it does not provide good predictions when used on new data. This situation is called overfitting: we have a very good fit in our training dataset, but predictions for new data inputs are bad.






























Figure 3.11: Examples of Overfitting and Underfitting



Figure 3.11 provides examples of overfitting and underfitting. The blue dots represent the training data \(x\) and \(y\), the orange curve represents the fit of the model to the training data. The left plot shows an example of underfitting: the model is too simple to capture the underlying structure of the data. The middle plot shows a “good fit”: the model captures the underlying structure of the data. The right plot shows an example of overfitting: the model is too complex and captures the noise in the data.



ML = require("https://www.lactame.com/lib/ml/6.0.0/ml.min.js")

// Parameters (defined outside to be accessible)
p = 0  // Parameter for true DGP: (x-p)^2
K = 5  // Number of data points
nTest = 50  // Number of test data points
xRange = [-6, 6]
yRange = [-5, 30]
noiseLevel = 2.0

// True data generating process: f(x) = (x - p)^2
trueDGP = (x) =&gt; Math.pow(x - p, 2)

// Generate training data with seeded RNG (seed = 42)
trainingSeed = 42 / 2147483647
trainingSource = d3.randomLcg(trainingSeed)
trainingRandn = d3.randomNormal.source(trainingSource)(0, 1)
trainingRandUniform = d3.randomUniform.source(trainingSource)(xRange[0], xRange[1])

// Generate K training data points
xTrainUnsorted = Array.from({length: K}, () =&gt; trainingRandUniform())
noiseTrainBase = Array.from({length: K}, () =&gt; trainingRandn())

// Create paired training data and sort by x
pairedTrainData = xTrainUnsorted.map((x, i) =&gt; ({x: x, noiseBase: noiseTrainBase[i]})).sort((a, b) =&gt; a.x - b.x)

xTrain = pairedTrainData.map(d =&gt; d.x)
yTrain = pairedTrainData.map(d =&gt; trueDGP(d.x) + d.noiseBase * noiseLevel)

// Create training data array for plotting
sampleData = xTrain.map((x, i) =&gt; ({x: x, y: yTrain[i]}))

// Generate test data with different seed (seed = 43)
testSeed = 43 / 2147483647
testSource = d3.randomLcg(testSeed)
testRandn = d3.randomNormal.source(testSource)(0, 1)
testRandUniform = d3.randomUniform.source(testSource)(xRange[0], xRange[1])

// Generate test data points
xTestUnsorted = Array.from({length: nTest}, () =&gt; testRandUniform())
noiseTestBase = Array.from({length: nTest}, () =&gt; testRandn())

// Create paired test data and sort by x
pairedTestData = xTestUnsorted.map((x, i) =&gt; ({x: x, noiseBase: noiseTestBase[i]})).sort((a, b) =&gt; a.x - b.x)

xTest = pairedTestData.map(d =&gt; d.x)
yTest = pairedTestData.map(d =&gt; trueDGP(d.x) + d.noiseBase * noiseLevel)

// Generate true DGP curve for plotting
trueCurveData = {
    let data = [];
    for (let i = 0; i &lt;= 100; i++) {
        let x = xRange[0] + i * (xRange[1] - xRange[0]) / 100;
        data.push({x: x, y: trueDGP(x)});
    }
    return data;
}

// Fit polynomial using ml.js PolynomialRegression
fitPoly = (degree) =&gt; {
    let powers = [];
    for (let d = 0; d &lt;= degree; d++) {
        powers.push(d);
    }
    return new ML.PolynomialRegression(xTrain, yTrain, powers);
}

// Compute MSE
computeMSE = (yTrue, yPred) =&gt; {
    let mse = 0;
    for (let i = 0; i &lt; yTrue.length; i++) {
        mse += Math.pow(yTrue[i] - yPred[i], 2);
    }
    return mse / yTrue.length;
}

// Compute RMSE for all polynomial orders (training and test)
rmseData = {
    let data = [];
    for (let degree = 0; degree &lt; K; degree++) {
        let model = fitPoly(degree);
        let yPredTrain = xTrain.map(x =&gt; model.predict(x));
        let yPredTest = xTest.map(x =&gt; model.predict(x));
        let mseTrain = computeMSE(yTrain, yPredTrain);
        let mseTest = computeMSE(yTest, yPredTest);
        // Compute RMSE (square root of MSE)
        let rmseTrain = Math.sqrt(mseTrain);
        let rmseTest = Math.sqrt(mseTest);
        data.push({k: degree, rmseTrain: rmseTrain, rmseTest: rmseTest});
    }
    return data;
}

// Compute max RMSE for y-axis scaling (separate for train and test)
maxRMSETrain = Math.max(...rmseData.map(d =&gt; d.rmseTrain))
maxRMSETest = Math.max(...rmseData.map(d =&gt; d.rmseTest))

// Fit polynomial of current order k (reactive to polyOrder)
currentModel = fitPoly(polyOrder)

// Generate fitted curve (reactive to polyOrder)
fittedCurveData = {
    let data = [];
    for (let i = 0; i &lt;= 200; i++) {
        let x = xRange[0] + i * (xRange[1] - xRange[0]) / 200;
        data.push({x: x, y: currentModel.predict(x)});
    }
    return data;
}























































































































































































































































