async function tokenizeText(text, currentModelId) {
  if (!text) return null;

  // Load tokenizer if needed
  if (!tokCache.tokenizer || tokCache.loadedModelId !== currentModelId) {
    tokCache.tokenizer = await transformers.AutoTokenizer.from_pretrained(currentModelId);
    tokCache.loadedModelId = currentModelId;
  }

  const tokenizer = tokCache.tokenizer;

  // Encode to get token IDs
  const encoded = tokenizer.encode(text);

  // Decode each token individually to get text representation
  const tokens = [];
  for (let i = 0; i &lt; encoded.length; i++) {
    const tokenText = tokenizer.decode([encoded[i]]);
    tokens.push({
      id: encoded[i],
      text: tokenText,
      color: tokColors[i % tokColors.length]
    });
  }

  return {
    tokens: tokens,
    tokenCount: encoded.length,
    charCount: text.length
  };
}

// Trigger tokenization
async function runTokenization(text, currentModelId) {
  mutable tokIsLoading = true;
  mutable tokErrorMessage = "";
  mutable tokTokenizerResult = null;

  try {
    const result = await tokenizeText(text, currentModelId);
    mutable tokTokenizerResult = result;
  } catch (err) {
    console.error(err);
    mutable tokErrorMessage = `Failed to load tokenizer: ${err.message}`;
  } finally {
    mutable tokIsLoading = false;
  }
}
















