  // Stats row
  if (tokTokenizerResult) {
    const statsRow = document.createElement('div');
    statsRow.className = 'tok-stats-row';

    const tokenStat = document.createElement('div');
    tokenStat.className = 'tok-stat';
    tokenStat.innerHTML = `&lt;span class="tok-stat-value"&gt;${tokTokenizerResult.tokenCount.toLocaleString()}&lt;/span&gt; tokens`;
    statsRow.appendChild(tokenStat);

    const charStat = document.createElement('div');
    charStat.className = 'tok-stat';
    charStat.innerHTML = `&lt;span class="tok-stat-value"&gt;${tokTokenizerResult.charCount.toLocaleString()}&lt;/span&gt; characters`;
    statsRow.appendChild(charStat);

