      const tooltip = document.createElement('span');
      tooltip.className = 'tok-token-tooltip';
      tooltip.textContent = `ID: ${token.id}`;
      span.appendChild(tooltip);

      outputBox.appendChild(span);
    });

    outputSection.appendChild(outputBox);

    // Token IDs section
    if (tokShowIds) {
      const idsLabel = document.createElement('div');
      idsLabel.className = 'tok-header-row';
