      idsLabelText.className = 'tok-label';
      idsLabelText.textContent = 'Token IDs';
      idsLabel.appendChild(idsLabelText);
      outputSection.appendChild(idsLabel);

      const idsBox = document.createElement('div');
      idsBox.className = 'tok-ids-box';

      tokTokenizerResult.tokens.forEach((token, idx) =&gt; {
