// Constants
DEBOUNCE_MS = 2500

// State management
mutable currentText = defaultText
mutable isLoading = false
mutable errorMessage = ""
mutable topTokens = []
mutable hasStarted = false
mutable showSettings = false
mutable modelId = "Xenova/gpt2"//"onnx-community/gpt2-mini-ONNX"
mutable quantization = "q4f16"//"q4f16"

// Model cache (non-reactive) - includes the modelId and quantization it was loaded with
modelCache = ({ model: null, tokenizer: null, loadedModelId: null, loadedQuantization: null })

// Request tracking for cancellation
requestCounter = ({ value: 0 })






















































































async function getTopTokens(text, currentModelId, currentQuantization) {
  if (!text.trim()) return [];

  // Load tokenizer and model if not already loaded or if model/quantization changed
  if (!modelCache.tokenizer || modelCache.loadedModelId !== currentModelId) {
    modelCache.tokenizer = await transformers.AutoTokenizer.from_pretrained(currentModelId);
  }
  if (!modelCache.model || modelCache.loadedModelId !== currentModelId || modelCache.loadedQuantization !== currentQuantization) {
    modelCache.model = await transformers.AutoModelForCausalLM.from_pretrained(currentModelId, { dtype: currentQuantization });
    modelCache.loadedModelId = currentModelId;
    modelCache.loadedQuantization = currentQuantization;
  }

  const tokenizer = modelCache.tokenizer;
  const model = modelCache.model;

  // Tokenize input
  const inputs = await tokenizer(text, { return_tensors: "pt" });

  // Run model forward pass
  const output = await model(inputs);

  // Get logits for the last token position
  const logits = output.logits;
  const [batchSize, seqLength, vocabSize] = logits.dims;
  const logitsData = logits.data;

  // Extract logits for the last token
  const lastTokenStart = (seqLength - 1) * vocabSize;
  const lastTokenLogits = logitsData.slice(lastTokenStart, lastTokenStart + vocabSize);

  // Find max logit for numerical stability
  let maxLogit = -Infinity;
  for (let i = 0; i &lt; lastTokenLogits.length; i++) {
    if (lastTokenLogits[i] &gt; maxLogit) maxLogit = lastTokenLogits[i];
  }

  // Compute softmax and collect all probabilities with indices
  let sumExp = 0;
  const expLogits = new Float32Array(lastTokenLogits.length);
  for (let i = 0; i &lt; lastTokenLogits.length; i++) {
    expLogits[i] = Math.exp(lastTokenLogits[i] - maxLogit);
    sumExp += expLogits[i];
  }

  // Get top 5 tokens
  const tokenProbs = [];
  for (let i = 0; i &lt; expLogits.length; i++) {
    tokenProbs.push({ index: i, prob: expLogits[i] / sumExp });
  }
  tokenProbs.sort((a, b) =&gt; b.prob - a.prob);
  const top5 = tokenProbs.slice(0, 5);

  // Decode tokens
  return top5.map(t =&gt; ({
    token: tokenizer.decode([t.index]),
    probability: t.prob
  }));
}

// Shared function to trigger predictions with race condition protection
async function triggerPrediction(text, currentModelId, currentQuantization) {
  if (!text.trim()) {
    mutable topTokens = [];
    mutable errorMessage = "";
    return;
  }

  // Increment request counter to track this request
  const thisRequest = ++requestCounter.value;

  mutable isLoading = true;
  mutable topTokens = [];
  mutable hasStarted = true;
  mutable errorMessage = "";

  try {
    const tokens = await getTopTokens(text, currentModelId, currentQuantization);
    // Only update if this is still the latest request
    if (thisRequest === requestCounter.value) {
      mutable topTokens = tokens;
    }
  } catch (err) {
    console.error(err);
    // Only show error if this is still the latest request
    if (thisRequest === requestCounter.value) {
      mutable errorMessage = "Failed to load model. Please check the model ID and try again.";
    }
  } finally {
    // Only clear loading if this is still the latest request
    if (thisRequest === requestCounter.value) {
      mutable isLoading = false;
    }
  }
}
















