  }

  // Handle text input changes (debounced with visual indicator)
  let debounceTimer;
  textInput.addEventListener('input', (e) =&gt; {
    clearTimeout(debounceTimer);
    // Show typing indicator with countdown circle
    typingIndicator.innerHTML = `
      &lt;svg class="llm-countdown-circle" viewBox="0 0 14 14"&gt;
