    `;

    debounceTimer = setTimeout(() =&gt; {
      // Hide typing indicator
      typingIndicator.innerHTML = '';
      const newText = e.target.value;
      mutable currentText = newText;
      // Generate new predictions using shared function
      triggerPrediction(newText, modelId, quantization);
    }, DEBOUNCE_MS);
  });

  // Enter submits, Shift+Enter creates a newline
  textInput.addEventListener('keydown', (e) =&gt; {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      clearTimeout(debounceTimer);
      typingIndicator.innerHTML = '';
