async function generateNextToken(text, currentModelId, currentQuantization, temperature) {
  // Load tokenizer and model if not already loaded (uses shared cache)
  if (!modelCache.tokenizer || modelCache.loadedModelId !== currentModelId) {
    modelCache.tokenizer = await transformers.AutoTokenizer.from_pretrained(currentModelId);
  }
  if (!modelCache.model || modelCache.loadedModelId !== currentModelId || modelCache.loadedQuantization !== currentQuantization) {
    modelCache.model = await transformers.AutoModelForCausalLM.from_pretrained(currentModelId, { dtype: currentQuantization });
    modelCache.loadedModelId = currentModelId;
    modelCache.loadedQuantization = currentQuantization;
  }

  const tokenizer = modelCache.tokenizer;
  const model = modelCache.model;

  // Tokenize input
  const inputs = await tokenizer(text, { return_tensors: "pt" });

  // Run model forward pass
  const output = await model(inputs);

  // Get logits for the last token position
  const logits = output.logits;
  const [batchSize, seqLength, vocabSize] = logits.dims;
  const logitsData = logits.data;

  // Extract logits for the last token
  const lastTokenStart = (seqLength - 1) * vocabSize;
  const lastTokenLogits = logitsData.slice(lastTokenStart, lastTokenStart + vocabSize);

  let selectedIdx;

  if (temperature === 0) {
    // Greedy decoding: select token with highest logit
    selectedIdx = 0;
    let maxVal = lastTokenLogits[0];
    for (let i = 1; i &lt; lastTokenLogits.length; i++) {
      if (lastTokenLogits[i] &gt; maxVal) {
        maxVal = lastTokenLogits[i];
        selectedIdx = i;
      }
    }
  } else {
    // Temperature sampling: divide logits by temperature, apply softmax, sample
    // Find max logit for numerical stability
    let maxLogit = -Infinity;
    for (let i = 0; i &lt; lastTokenLogits.length; i++) {
      if (lastTokenLogits[i] &gt; maxLogit) maxLogit = lastTokenLogits[i];
    }

    // Compute softmax with temperature
    let sumExp = 0;
    const probs = new Float32Array(lastTokenLogits.length);
    for (let i = 0; i &lt; lastTokenLogits.length; i++) {
      probs[i] = Math.exp((lastTokenLogits[i] - maxLogit) / temperature);
      sumExp += probs[i];
    }

    // Normalize to get probabilities
    for (let i = 0; i &lt; probs.length; i++) {
      probs[i] /= sumExp;
    }

    // Sample from the distribution
    const rand = Math.random();
    let cumSum = 0;
    selectedIdx = probs.length - 1; // Default to last token
    for (let i = 0; i &lt; probs.length; i++) {
      cumSum += probs[i];
      if (rand &lt; cumSum) {
        selectedIdx = i;
        break;
      }
    }
  }

  // Check for end-of-text token
  const eosTokenId = tokenizer.eos_token_id;
  if (selectedIdx === eosTokenId) {
    return null; // Signal end of generation
  }

  // Decode and return the token
  return tokenizer.decode([selectedIdx]);
}

// Helper to yield to the event loop and allow UI updates
function yieldToUI() {
  return new Promise(resolve =&gt; setTimeout(resolve, 0));
}

// Main generation loop - uses genPromptStore to get current prompt value
async function runGeneration(maxTokens, currentModelId, currentQuantization, temperature) {
  const prompt = genPromptStore.value;
  genStopFlag.value = false;
  mutable genCompletion = "";
  mutable genIsGenerating = true;
  mutable genErrorMessage = "";
  mutable genShowCompletion = true;

  let currentText = prompt;
  let tokensGenerated = 0;

  try {
    while (tokensGenerated &lt; maxTokens && !genStopFlag.value) {
      const nextToken = await generateNextToken(currentText, currentModelId, currentQuantization, temperature);

      if (nextToken === null) {
        // End of text reached
        break;
      }

      currentText += nextToken;
      mutable genCompletion = currentText.slice(prompt.length);
      tokensGenerated++;

      // Yield to event loop to allow UI to update after each token
      await yieldToUI();
    }
  } catch (err) {
    console.error(err);
    mutable genErrorMessage = "Generation failed. Please check the model ID and try again.";
  } finally {
    mutable genIsGenerating = false;
  }
}























