  };
  setTimeout(autoResizePrompt, 0);

  // Update store on input (doesn't trigger re-render)
  promptInput.addEventListener('input', (e) =&gt; {
    autoResizePrompt();
    genPromptStore.value = e.target.value;
  });

  inputRow.appendChild(promptInput);

  // Generate or Stop button (reuses llm-action-btn style from first app)
  const actionBtn = document.createElement('button');
  actionBtn.className = 'llm-action-btn';

  if (genIsGenerating) {
    actionBtn.textContent = 'Stop';
    actionBtn.style.background = '#d32f2f';
    actionBtn.style.borderColor = '#d32f2f';
    actionBtn.style.color = 'white';
    actionBtn.addEventListener('click', () =&gt; {
      genStopFlag.value = true;
    });
  } else {
    actionBtn.textContent = 'Generate';
    actionBtn.addEventListener('click', () =&gt; {
      runGeneration(genMaxTokens, genModelId, genQuantization, genTemperature);
    });
  }
  inputRow.appendChild(actionBtn);

  container.appendChild(inputRow);

  // Error message (shown above completion)
  if (genErrorMessage) {
    const errorDiv = document.createElement('div');
    errorDiv.className = 'gen-error';
    errorDiv.setAttribute('role', 'alert');
    errorDiv.textContent = genErrorMessage;
    container.appendChild(errorDiv);
  }

  // Completion section (only shown after generation starts)
  if (genShowCompletion) {
    const completionSection = document.createElement('div');
    completionSection.className = 'gen-section';
    completionSection.style.marginTop = '16px';

    const completionHeaderRow = document.createElement('div');
    completionHeaderRow.className = 'gen-header-row';

    const completionLabel = document.createElement('div');
    completionLabel.className = 'gen-label';
    completionLabel.textContent = 'Completion';
    completionHeaderRow.appendChild(completionLabel);

    // Right side: generating indicator + clear button
    const headerRight = document.createElement('div');
    headerRight.className = 'gen-completion-header-right';

    // Generating indicator (inline, like typing indicator in first app)
    if (genIsGenerating) {
      const generatingIndicator = document.createElement('div');
      generatingIndicator.className = 'gen-generating-indicator';
      generatingIndicator.innerHTML = '&lt;div class="gen-spinner-small"&gt;&lt;/div&gt;&lt;span&gt;Generating...&lt;/span&gt;';
      headerRight.appendChild(generatingIndicator);
    }

    // Clear button
    const clearBtn = document.createElement('button');
    clearBtn.className = 'gen-clear-btn';
    clearBtn.textContent = 'Clear';
    clearBtn.addEventListener('click', () =&gt; {
      genPromptStore.value = genDefaultPrompt;
      mutable genPrompt = genDefaultPrompt;
      mutable genCompletion = "";
      mutable genErrorMessage = "";
      mutable genShowCompletion = false;
    });
    headerRight.appendChild(clearBtn);

    completionHeaderRow.appendChild(headerRight);
    completionSection.appendChild(completionHeaderRow);

    const completionBox = document.createElement('div');
    completionBox.className = 'gen-completion-box' + (genCompletion ? '' : ' empty');
    completionBox.textContent = genCompletion || 'Generated text will appear here...';
    completionSection.appendChild(completionBox);

    container.appendChild(completionSection);
  }

  return container;
}
